import React, { useState } from 'react'
import useToast from './useToast'
import Toast, { TOAST_TYPE } from './Toast.component'
import useToastStore from './useToastStore'

function Example() {
    const { openToast, closeToast } = useToast()
    const toasts = useToastStore((s) => s.toasts)
    function openSuccessToast() {
        let id = null
        id = openToast({
            message: 'This is a success toast',
            type: TOAST_TYPE.SUCCESS,
            id
        })
    }
    function openErrorToast() {
        let id = null
        id = openToast({
            message: 'This is a error toast',
            type: TOAST_TYPE.ERROR
        })
    }
    function openWarningToast(priority, count) {
        let id = null
        id = openToast({
            message: 'This is a warning toast',
            type: TOAST_TYPE.ERROR
        })
    }
    return (
        <>
            <button onClick={openSuccessToast}>Open Success Toast</button>
            <button onClick={openErrorToast}>Open Error Toast</button>
            <button onClick={() => openWarningToast(1, 1)}>Open Warning Toast 1</button>
            <button onClick={() => openWarningToast(12, 2)}>Open Warning Toast 2</button>
        </>
    )
}

export default Example
